"use client"
import { useState, useEffect } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { Play, Music2, X, Loader2, Sparkles, CheckCircle2, AlertCircle, User, Clock, Share2 } from "lucide-react"

// 1. Configuração de Negócio e Validação
const PLATFORMS = {
  youtube: {
    name: "YouTube",
    color: "text-red-600",
    bgGlow: "from-red-200/50",
    button: "bg-red-600",
    icon: <Play className="w-12 h-12 text-red-600" />,
    endpoint: "/youtube",
    regex: /^(https?:\/\/)?(www\.)?(youtube\.com|youtu\.be)\/.+$/
  },
  tiktok: {
    name: "TikTok",
    color: "text-zinc-900",
    bgGlow: "from-cyan-200/40 via-pink-200/40",
    button: "bg-zinc-900",
    icon: <Music2 className="w-12 h-12 text-zinc-900" />,
    endpoint: "/tiktok",
    regex: /^(https?:\/\/)?(www\.)?tiktok\.com\/.+$/
  },
  twitter: {
    name: "Twitter",
    color: "text-blue-500",
    bgGlow: "from-blue-200/50",
    button: "bg-black",
    icon: <X className="w-12 h-12 text-black" />,
    endpoint: "/twitter",
    regex: /^(https?:\/\/)?(www\.)?(twitter\.com|x\.com)\/.+$/
  }
}

const BACKEND_URL = "http://26.44.44.119:8000";

export default function Home() {
  const [activeTab, setActiveTab] = useState<keyof typeof PLATFORMS>("youtube")
  const [url, setUrl] = useState("") 
  const [loading, setLoading] = useState(false) 
  const [videoData, setVideoData] = useState<any>(null) 
  const [error, setError] = useState("")
  const [loadingStep, setLoadingStep] = useState(0)

  const current = PLATFORMS[activeTab]

  const loadingMessages = [
    "Estabelecendo conexão segura...",
    "O yt-dlp está lendo os metadados...",
    "A IA está processando o conteúdo...",
    "Formatando resumo inteligente...",
    "Finalizando detalhes visuais..."
  ];

  // Alterna as mensagens de loading automaticamente
  useEffect(() => {
    let interval: any;
    if (loading) {
      setLoadingStep(0);
      interval = setInterval(() => {
        setLoadingStep((prev) => (prev < loadingMessages.length - 1 ? prev + 1 : prev));
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleProcess = async () => {
    setError("");
    setVideoData(null);

    // Validação: Campo vazio
    if (!url.trim()) {
      setError("Por favor, cole um link para continuar.");
      return;
    }

    // Validação: Link pertence à plataforma selecionada?
    if (!current.regex.test(url)) {
      setError(`Este link não parece ser um URL válido do ${current.name}.`);
      return;
    }

    setLoading(true);

    try {
      const res = await fetch(`${BACKEND_URL}${current.endpoint}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url: url })
      });
      
      if (!res.ok) throw new Error("Falha na resposta do servidor.");

      const data = await res.json();
      
      // Ajuste para capturar data.dados como solicitado
      if (data.dados) {
        setVideoData(data.dados);
      } else {
        setVideoData(data);
      }

    } catch (err) {
      setError("Não foi possível conectar ao servidor. O Radmin está ativo?");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className={`min-h-screen relative overflow-hidden transition-colors duration-700 bg-white flex flex-col items-center pb-20`}>
      {/* Background Effect */}
      <div className={`absolute inset-0 bg-gradient-to-b ${current.bgGlow} to-white -z-10`} />

      {/* Navigation */}
      <nav className="flex justify-center gap-8 p-8 text-sm font-bold tracking-widest uppercase text-zinc-400 z-10">
        {Object.keys(PLATFORMS).map((id) => (
          <button 
            key={id}
            onClick={() => { setActiveTab(id as any); setVideoData(null); setUrl(""); setError(""); setLoading(false) }}
            className={`transition-all duration-300 ${activeTab === id ? 'text-zinc-900 border-b-2 border-zinc-900' : 'hover:text-zinc-600'}`}
          >
            {id}
          </button>
        ))}
      </nav>

      <div className="max-w-4xl w-full flex flex-col items-center justify-center pt-12 px-4 z-10">
        <AnimatePresence mode="wait">
          <motion.div
            key={activeTab}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="flex flex-col items-center text-center w-full"
          >
            <motion.div 
              initial={{ scale: 0.8 }} 
              animate={{ scale: 1 }} 
              className="mb-6"
            >
              {current.icon}
            </motion.div>

            <h1 className="text-6xl font-black tracking-tighter mb-10 text-zinc-900">
              Aura <span className={current.color}>Summarizer</span>
            </h1>

            {/* Input Section */}
            <div className="relative w-full max-w-xl space-y-4">
              <div className="relative">
                <input
                  type="text"
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                  placeholder="Cole a URL aqui..."
                  className={`w-full py-5 px-8 rounded-full border-2 transition-all bg-white/90 backdrop-blur-sm shadow-2xl focus:outline-none focus:ring-4 focus:ring-opacity-10 ${error ? 'border-red-500 ring-red-100' : 'border-black/5 focus:border-zinc-400'}`}
                />
                <AnimatePresence>
                  {error && (
                    <motion.p 
                      initial={{ opacity: 0, x: -10 }} 
                      animate={{ opacity: 1, x: 0 }} 
                      exit={{ opacity: 0 }}
                      className="absolute -bottom-7 left-6 text-red-500 text-xs font-bold flex items-center gap-1"
                    >
                      <AlertCircle size={12}/> {error}
                    </motion.p>
                  )}
                </AnimatePresence>
              </div>

              <button
                onClick={handleProcess}
                disabled={loading}
                className={`w-full py-5 rounded-full font-black text-lg text-white shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${current.button} hover:brightness-110 disabled:opacity-50`}
              >
                {loading ? <Loader2 className="animate-spin" /> : "Gerar Resumo Foda"}
              </button>
            </div>

            {/* Loading Display */}
            {loading && (
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="mt-10 flex flex-col items-center gap-3">
                <div className="flex items-center gap-2 text-zinc-500 font-bold italic text-sm">
                  <Sparkles className="text-yellow-500 animate-pulse" size={16} />
                  {loadingMessages[loadingStep]}
                </div>
                <div className="w-48 h-1 bg-zinc-100 rounded-full overflow-hidden">
                  <motion.div 
                    className={`h-full ${current.button}`} 
                    initial={{ width: "0%" }} 
                    animate={{ width: "100%" }} 
                    transition={{ duration: 15 }} 
                  />
                </div>
              </motion.div>
            )}

            {/* Result Card */}
            {videoData && (
              <motion.div
                initial={{ opacity: 0, y: 40 }}
                animate={{ opacity: 1, y: 0 }}
                className="mt-16 w-full max-w-2xl bg-white rounded-[2.5rem] shadow-[0_32px_64px_-15px_rgba(0,0,0,0.1)] border border-zinc-100 overflow-hidden text-left"
              >
                {videoData.thumbnail && (
                  <div className="w-full h-56 overflow-hidden relative border-b border-zinc-50">
                    <img src={videoData.thumbnail} alt="Capa" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent flex items-end p-8">
                       <div className="flex gap-3">
                          <span className="text-white text-xs font-bold bg-white/20 px-3 py-1.5 rounded-full backdrop-blur-md flex items-center gap-1">
                            <Clock size={12}/> {videoData.duracao || "Vídeo"}
                          </span>
                       </div>
                    </div>
                  </div>
                )}

                <div className="p-8 space-y-6">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1">
                      <h2 className="text-3xl font-black text-zinc-900 leading-tight tracking-tight">
                        {videoData.titulo || "Sem título"}
                      </h2>
                      <p className="text-zinc-400 font-bold text-sm flex items-center gap-1.5">
                        <User size={14} className={current.color}/> {videoData.autor || "Desconhecido"}
                      </p>
                    </div>
                    <div className={`p-3 rounded-2xl bg-zinc-50 text-emerald-500 shadow-sm`}>
                      <CheckCircle2 size={24} />
                    </div>
                  </div>

                  <div className="bg-zinc-50/80 p-6 rounded-[2rem] border border-zinc-100 relative">
                    <div className="absolute -top-3 left-6 bg-white px-3 py-1 rounded-full border border-zinc-100 text-[10px] font-black uppercase tracking-widest text-zinc-400 flex items-center gap-1">
                      <Sparkles size={10} className="text-yellow-500"/> Inteligência Artificial
                    </div>
                    <p className="text-zinc-700 leading-relaxed font-semibold text-lg">
                      {videoData.resumo || "O resumo está sendo processado e aparecerá aqui em instantes."}
                    </p>
                  </div>
                  
                  <button className="w-full py-4 border-2 border-zinc-100 rounded-2xl font-bold text-zinc-400 hover:bg-zinc-50 transition-colors flex items-center justify-center gap-2">
                    <Share2 size={16}/> Compartilhar Resumo
                  </button>
                </div>
              </motion.div>
            )}
          </motion.div>
        </AnimatePresence>
      </div>
    </main>
  )
}